function candidate(path) {
  let limit = path.length;
  while (limit > 0 && path[limit - 1] === "/") limit--;

  const root = path[0] === "/" ? "/" : "";

  if (limit === 0) {
    return { root, dir: root, base: "", ext: "", name: "" };
  }

  let split = -1;
  for (let i = limit - 1; i >= 0; i--) {
    if (path[i] === "/") {
      split = i;
      break;
    }
  }

  const base = path.slice(split + 1, limit);
  let dir = "";
  if (split === 0 && root) dir = "/";
  else if (split > 0) dir = path.slice(0, split);

  let dot = -1;
  for (let i = base.length - 1; i >= 0; i--) {
    if (base[i] === ".") {
      dot = i;
      break;
    }
  }

  let ext = "";
  let name = base;
  if (dot > 0 && !/^\.+$/.test(base)) {
    ext = base.slice(dot);
    name = base.slice(0, dot);
  }

  return { root, dir, base, ext, name };
}
